sql:
SELECT DISTINCT l.product
FROM laptops l
JOIN reviews r ON l.laptop_id = r.laptop_id;

SELECT laptop_id, product, price_euros, stock_quantity
FROM laptops
ORDER BY price_euros DESC;

SELECT product, type_name, AVG(price_euros) AS average_price, MAX(stock_quantity) AS max_stock
FROM laptops
GROUP BY product, type_name;

SELECT AVG(price_euros) AS average_price, product
FROM laptops
GROUP BY product;

SELECT product 
FROM laptops 
WHERE price_euros = (SELECT MIN(price_euros) FROM laptops);

external_knowledge:
- "branch 1": Refers to the branch with branch_id 1;
- "this year": Refers to the year 2023;
- "brought in the most cash": Refers to the laptops that generated the highest total revenue;
- "total sales count": Represents the total quantity sold for each model;
- "earnings for each model": Refers to the total revenue from each model.

sql:
WITH TypicalPrice AS (
    SELECT AVG(price_euros) AS typical_price FROM laptops
)
SELECT product, tp.typical_price
FROM laptops, TypicalPrice tp
WHERE laptops.price_euros > tp.typical_price;
